import threading
import time
from limiter import rate_limit, RateLimitError

@rate_limit(max_calls=3, period=1.0)
def limited_function():
    return True

def test_basic_limit():
    # Should allow 3 calls
    limited_function()
    limited_function()
    limited_function()
    try:
        limited_function()
        print("FAIL: Expected RateLimitError")
    except RateLimitError:
        print("PASS: RateLimitError raised")

def test_time_window():
    # Should reset after period
    time.sleep(1.1)
    limited_function()
    print("PASS: Allowed after period")

def test_thread_safety():
    results = []
    errors = []

    @rate_limit(max_calls=10, period=2.0)
    def fast_function():
        time.sleep(0.01)
        return True

    def worker():
        try:
            if fast_function():
                results.append(1)
        except RateLimitError:
            errors.append(1)

    threads = [threading.Thread(target=worker) for _ in range(20)]
    for t in threads:
        t.start()
    for t in threads:
        t.join()

    print(f"Total results: {len(results)}")
    print(f"Total errors: {len(errors)}")

    if len(results) == 10 and len(errors) == 10:
        print("PASS: Thread safety verified")
    else:
        print("FAIL: Thread safety verification failed")

if __name__ == "__main__":
    print("Running basic limit test...")
    test_basic_limit()
    print("\nRunning time window test...")
    test_time_window()
    print("\nRunning thread safety test...")
    test_thread_safety()

